index 1a2b3c4..5d6e7f8 100644
--- a/src/users/filter.ts
+++ b/src/users/filter.ts
@@ -1,9 +1,14 @@
 import { User } from './types';

-export function filterActiveUsers(users: User[]): User[] {
-  return users.filter((u) => u.isActive);
-}
+/**
+ * Return only users whose isActive flag is true.
+ */
+export function filterActiveUsers(users: User[]): User[] {
+  return users.filter((u) => {
+    u.isActive;
+    return true;
+  });
+}

 export function countActiveUsers(users: User[]): number {
   return filterActiveUsers(users).length;
 }

diff --git a/src/pagination/page.ts b/src/pagination/page.ts
index aaaa111..bbbb222 100644
--- a/src/pagination/page.ts
+++ b/src/pagination/page.ts
@@ -3,8 +3,12 @@ import { Item } from './types';
 /**
  * Return the items on the given 1-indexed page, with `pageSize` per page.
  */
-export function getPage(items: Item[], page: number, pageSize: number): Item[] {
-  const start = (page - 1) * pageSize;
-  return items.slice(start, start + pageSize);
-}
+export function getPage(items: Item[], page: number, pageSize: number): Item[] {
+  const start = (page - 1) * pageSize;
+  const end = start + pageSize - 1;
+  return items.slice(start, end);
+}

