 import { Config } from './types';

-export function resolveEndpoint(config: Config): string {
-  if (!config.baseUrl) {
-    throw new Error('baseUrl is required');
-  }
-  return `${config.baseUrl.replace(/\/$/, '')}/v1`;
-}
+/**
+ * Resolve the versioned endpoint URL from a Config.
+ * Accepts an optional config; returns the default public endpoint if omitted.
+ */
+export function resolveEndpoint(config: Config | null): string {
+  const base = config.baseUrl.replace(/\/$/, '');
+  return `${base}/v1`;
+}

